function createvideocard(){
    for (let aaab = 0; aaab < videodata.length; aaab++) {
        // 定义自定义文本内容
        const imgSrc = videodata[aaab].base64;
        const cardTitle = videodata[aaab].title;
        const cardDes = videodata[aaab].jj;
        const buttonFunction = "window.open('lookvideo.html#"+(aaab+1)+"')";

        // 获取目标容器
        const videoLists = document.getElementById('videolists');

        // 创建卡片元素
        const card = document.createElement('div');
        card.classList.add('card');

        // 创建卡片图像容器
        const cardImageContainer = document.createElement('div');
        cardImageContainer.classList.add('card-image-container');
        const img = document.createElement('img');
        img.src = imgSrc;
        cardImageContainer.appendChild(img);

        // 创建卡片标题
        const cardTitleElement = document.createElement('p');
        cardTitleElement.classList.add('card-title');
        cardTitleElement.textContent = cardTitle;

        // 创建卡片描述
        const cardDesElement = document.createElement('p');
        cardDesElement.classList.add('card-des');
        cardDesElement.textContent = cardDes;

        // 创建卡片按钮容器
        const cardBtn = document.createElement('div');
        cardBtn.classList.add('card-btn');
        cardBtn.setAttribute('onclick', buttonFunction);
        const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
        svg.setAttribute('xmlns', 'http://www.w3.org/2000/svg');
        svg.setAttribute('width', '1em');
        svg.setAttribute('height', '1em');
        svg.setAttribute('viewBox', '0 0 384 512');
        svg.setAttribute('stroke-width', '0');
        svg.setAttribute('fill', 'currentColor');
        svg.setAttribute('stroke', 'currentColor');
        svg.innerHTML = '<path d="M73 39c-14.8-9.1-33.4-9.4-48.5-.9S0 62.6 0 80V432c0 17.4 9.4 33.4 24.5 41.9s33.7 8.1 48.5-.9L361 297c14.3-8.7 23-24.2 23-41s-8.7-32.2-23-41L73 39z"></path>';
        const cardBtnText = document.createElement('span');
        cardBtnText.classList.add('card-btn-text');
        cardBtnText.textContent = "立即观看！";
        cardBtn.appendChild(svg);
        cardBtn.appendChild(cardBtnText);

        // 将各个元素添加到卡片中
        card.appendChild(cardImageContainer);
        card.appendChild(cardTitleElement);
        card.appendChild(cardDesElement);
        card.appendChild(cardBtn);

        // 将卡片添加到目标容器中
        videoLists.appendChild(card);
    }
}
